import { useMemo, useRef, useState } from "react";

const API_BASE = "http://localhost:4000";

function App() {
  const videoRef = useRef(null);
  const janusRef = useRef(null);
  const pluginRef = useRef(null);
  const streamRef = useRef(null);
  const startedAtRef = useRef(0);

  const [candidateId, setCandidateId] = useState("");
  const [session, setSession] = useState(null);
  const [status, setStatus] = useState("Idle");
  const [busy, setBusy] = useState(false);

  const canStart = useMemo(() => Boolean(session?.room_id), [session]);

  const createSession = async () => {
    setBusy(true);
    setStatus("Creating interview session...");
    try {
      const response = await fetch(`${API_BASE}/session/create`, {
        method: "POST",
        headers: { "content-type": "application/json" },
        body: JSON.stringify({
          candidate_id: candidateId || undefined
        })
      });
      const data = await response.json();
      if (!response.ok) {
        throw new Error(data?.details || "Unable to create session");
      }
      setSession(data);
      setStatus("Session ready. Click Start interview.");
    } catch (error) {
      setStatus(error instanceof Error ? error.message : String(error));
    } finally {
      setBusy(false);
    }
  };

  const initJanus = async (wsUrl) => {
    const Janus = window.Janus;
    if (!Janus) {
      throw new Error("Janus JS client is not loaded.");
    }

    await new Promise((resolve, reject) => {
      Janus.init({
        debug: "all",
        callback: () => resolve(true)
      });
      setTimeout(() => reject(new Error("Janus initialization timeout")), 8000);
    });

    return new Promise((resolve, reject) => {
      janusRef.current = new Janus({
        server: wsUrl,
        iceServers: [{ urls: "stun:stun.l.google.com:19302" }],
        success: () => resolve(true),
        error: (err) => reject(err),
        destroyed: () => setStatus("Janus session destroyed")
      });
    });
  };

  const startInterview = async () => {
    if (!session) {
      setStatus("Create session first.");
      return;
    }

    setBusy(true);
    setStatus("Requesting camera and microphone...");
    try {
      const media = await navigator.mediaDevices.getUserMedia({
        video: true,
        audio: true
      });
      streamRef.current = media;
      videoRef.current.srcObject = media;
      startedAtRef.current = Date.now();

      await initJanus(session.janus_ws_url);
      setStatus("Connecting to Janus VideoRoom...");

      await new Promise((resolve, reject) => {
        janusRef.current.attach({
          plugin: "janus.plugin.videoroom",
          success: (pluginHandle) => {
            pluginRef.current = pluginHandle;
            pluginHandle.send({
              message: {
                request: "join",
                ptype: "publisher",
                room: session.room_id,
                display: candidateId || "candidate"
              }
            });
            resolve(true);
          },
          error: (err) => reject(err),
          onmessage: (msg, jsep) => {
            const event = msg?.videoroom;
            if (event === "joined") {
              publishOwnFeed(msg.id);
            }
            if (event === "event" && msg?.error) {
              setStatus(`Janus error: ${msg.error}`);
            }
            if (jsep && pluginRef.current) {
              pluginRef.current.handleRemoteJsep({ jsep });
            }
          },
          oncleanup: () => setStatus("Publisher cleaned up.")
        });
      });
    } catch (error) {
      setStatus(error instanceof Error ? error.message : String(error));
    } finally {
      setBusy(false);
    }
  };

  const publishOwnFeed = async () => {
    const plugin = pluginRef.current;
    const media = streamRef.current;
    if (!plugin || !media || !session) {
      return;
    }

    setStatus("Publishing stream and enabling server recording...");
    plugin.createOffer({
      tracks: [
        { type: "audio", capture: media.getAudioTracks()[0], recv: false },
        { type: "video", capture: media.getVideoTracks()[0], recv: false }
      ],
      success: (jsep) => {
        plugin.send({
          message: {
            request: "publish",
            audio: true,
            video: true,
            record: true,
            filename: session.session_id
          },
          jsep
        });
        setStatus("Live. Janus is recording on the server.");
      },
      error: (err) => {
        setStatus(`Publish failed: ${err?.message || err}`);
      }
    });
  };

  const stopInterview = async () => {
    setBusy(true);
    setStatus("Stopping interview...");
    try {
      pluginRef.current?.send({ message: { request: "unpublish" } });
      pluginRef.current?.hangup();
      janusRef.current?.destroy();
      streamRef.current?.getTracks().forEach((track) => track.stop());
      if (videoRef.current) {
        videoRef.current.srcObject = null;
      }

      if (session?.session_id) {
        const durationSeconds = Math.max(
          1,
          Math.round((Date.now() - startedAtRef.current) / 1000)
        );
        await fetch(`${API_BASE}/session/${session.session_id}/end`, {
          method: "POST",
          headers: { "content-type": "application/json" },
          body: JSON.stringify({ duration_seconds: durationSeconds })
        });
      }

      setStatus("Interview ended. You can process recordings from backend.");
    } catch (error) {
      setStatus(error instanceof Error ? error.message : String(error));
    } finally {
      setBusy(false);
    }
  };

  return (
    <main className="container">
      <h1>Candidate Interview Recorder (MVP)</h1>
      <p className="muted">
        Local stack: React candidate app + Node control API + Janus recording.
      </p>

      <section className="card">
        <label htmlFor="candidateId">Candidate ID (optional)</label>
        <input
          id="candidateId"
          value={candidateId}
          placeholder="candidate_001"
          onChange={(event) => setCandidateId(event.target.value)}
        />
        <div className="row">
          <button onClick={createSession} disabled={busy}>
            1) Create Session
          </button>
          <button onClick={startInterview} disabled={busy || !canStart}>
            2) Start Interview
          </button>
          <button onClick={stopInterview} disabled={busy || !canStart}>
            3) End Interview
          </button>
        </div>
      </section>

      <section className="card">
        <h2>Local Preview</h2>
        <video ref={videoRef} autoPlay playsInline muted className="preview" />
      </section>

      <section className="card">
        <h2>Status</h2>
        <pre>{status}</pre>
        {session ? (
          <pre>{JSON.stringify(session, null, 2)}</pre>
        ) : (
          <p className="muted">No session created yet.</p>
        )}
      </section>
    </main>
  );
}

export default App;
